-- Turkish Taxi Job - Server Side\nlocal QBCore = exports['qb-core']:GetCoreObject()\n\nlocal TaxiData = {}\n\nlocal TaxiLocations = {\n    {name = 'Taksim Duragi', x = 425.5, y = -980.2, z = 28.4, h = 180.0},\n    {name = 'Eminonu Duragi', x = -520.5, y = -1020.3, z = 22.0, h = 90.0},\n    {name = 'Kadikoy Duragi', x = 1150.0, y = -800.0, z = 57.6, h = 270.0},\n}\n\nRegisterNetEvent('taxi:server:startJob')\nAddEventHandler('taxi:server:startJob', function()\n    local src = source\n    local Player = QBCore.Functions.GetPlayer(src)\n    if not Player then return end\n    \n    TaxiData[src] = {active = true, earnings = 0, rides = 0, startTime = os.time()}\n    TriggerClientEvent('QBCore:Notify', src, 'Taksi isi basladi!', 'success')\nend)\n\nRegisterNetEvent('taxi:server:completeRide')\nAddEventHandler('taxi:server:completeRide', function(fare)\n    local src = source\n    local Player = QBCore.Functions.GetPlayer(src)\n    if not Player or not TaxiData[src] then return end\n    \n    TaxiData[src].earnings = TaxiData[src].earnings + fare\n    TaxiData[src].rides = TaxiData[src].rides + 1\n    Player.Functions.AddMoney('cash', fare)\n    TriggerClientEvent('QBCore:Notify', src, 'Yolculuk tamamlandi! +$' .. fare, 'success')\nend)\n\nprint('^2[Turkish Taxi Job] Yuklendi!^7')"